const checkpoints = [];

const subscriptions = JSON.parse(localStorage.getItem('subscriptions') || '[]');
const plans = JSON.parse(localStorage.getItem('pricing_plans') || '[]');

// Determine the most recent active/trial subscription (same logic as _getCurrentSubscription)
const activeSubs = subscriptions.filter(s => s.status === 'active' || s.status === 'trial');
let currentSub = null;
let currentPlan = null;
if (activeSubs.length > 0) {
  activeSubs.sort((a, b) => {
    const da = a.signup_at ? new Date(a.signup_at) : new Date(0);
    const db = b.signup_at ? new Date(b.signup_at) : new Date(0);
    return db - da; // newest first
  });
  currentSub = activeSubs[0];
  currentPlan = plans.find(p => p.id === currentSub.plan_id) || null;
}

// All plans that match the task criteria
const qualifyingPlans = plans.filter(p => (
  p.status === 'active' &&
  p.billing_period === 'monthly' &&
  Number(p.monthly_price) <= 40 &&
  Number(p.max_chatbots) >= 3 &&
  !!p.includes_conversation_analytics
));

let cheapestPlan = null;
if (qualifyingPlans.length > 0) {
  cheapestPlan = qualifyingPlans
    .slice()
    .sort((a, b) => Number(a.monthly_price) - Number(b.monthly_price))[0];
}

// CP1 (0.5): User's latest active/trial subscription is on a plan that satisfies all constraints
const cp1Passed = !!(currentPlan && qualifyingPlans.some(p => p.id === currentPlan.id));
checkpoints.push({ passed: cp1Passed, weight: 0.5 });

// CP2 (0.5): That plan is the cheapest among all qualifying plans
const cp2Passed = !!(cp1Passed && cheapestPlan && currentPlan.id === cheapestPlan.id);
checkpoints.push({ passed: cp2Passed, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const chatbots = JSON.parse(localStorage.getItem('chatbots') || '[]');
const templates = JSON.parse(localStorage.getItem('chatbot_templates') || '[]');

// Find the first active template that has BOTH Customer Support and E-commerce categories
const activeTemplates = templates.filter(t => t.status === 'active');
let firstMatchingTemplate = null;
for (const t of activeTemplates) {
  const cats = (t.categories || []).map(c => String(c).toLowerCase());
  if (cats.includes('customer support'.toLowerCase()) && cats.includes('e-commerce'.toLowerCase())) {
    firstMatchingTemplate = t;
    break;
  }
}

// Find a chatbot that matches the requested configuration
const desiredName = 'Store Support Bot';
const desiredLanguage = 'English';
const desiredGreeting = 'Hi! I can help you with orders, shipping, and returns today.';

let matchingBot = null;
for (const cb of chatbots) {
  if (cb.name === desiredName && cb.primary_language === desiredLanguage && cb.greeting_message === desiredGreeting) {
    const tmpl = templates.find(t => t.id === cb.template_id && t.status === 'active');
    if (tmpl) {
      const cats = (tmpl.categories || []).map(c => String(c).toLowerCase());
      if (cats.includes('customer support'.toLowerCase()) && cats.includes('e-commerce'.toLowerCase())) {
        matchingBot = cb;
        break;
      }
    }
  }
}

// CP1 (0.6): A chatbot exists with the exact name, language, greeting, and a template labeled for both Customer Support and E-commerce
const cp1Passed = !!matchingBot;
checkpoints.push({ passed: cp1Passed, weight: 0.6 });

// CP2 (0.4): That bot was created from the FIRST matching active template in the gallery
const cp2Passed = !!(cp1Passed && firstMatchingTemplate && matchingBot.template_id === firstMatchingTemplate.id);
checkpoints.push({ passed: cp2Passed, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const articles = JSON.parse(localStorage.getItem('kb_articles') || '[]');
const categories = JSON.parse(localStorage.getItem('kb_categories') || '[]');

const expectedFaqs = [
  {
    question: 'How long does shipping take?',
    answer: 'Standard shipping takes 35 business days within the US.',
    categoryName: 'Shipping'
  },
  {
    question: 'What is your return policy?',
    answer: 'You can return unused items within 30 days for a full refund.',
    categoryName: 'Returns'
  },
  {
    question: 'How can I check my order status?',
    answer: 'You can track your order using the tracking link sent after purchase or by providing your order ID in the chat.',
    categoryName: 'Orders'
  }
];

// Group by chatbot_id and look for a chatbot that has all three FAQs correctly configured
let bestResult = null;
const chatbotIds = Array.from(new Set(articles.map(a => a.chatbot_id).filter(Boolean)));

for (const cbId of chatbotIds) {
  const cbArticles = articles.filter(a => a.chatbot_id === cbId);

  const resultForCb = {
    chatbot_id: cbId,
    topicsComplete: false,
    correctCategories: false,
    exactlyThree: false
  };

  const found = {};
  for (const cfg of expectedFaqs) {
    const art = cbArticles.find(a => a.question === cfg.question && a.answer === cfg.answer);
    if (!art) {
      found[cfg.question] = null;
      continue;
    }
    const cat = categories.find(c => c.id === art.category_id) || null;
    found[cfg.question] = { article: art, category: cat };
  }

  const allPresent = expectedFaqs.every(cfg => !!found[cfg.question]);
  if (!allPresent) continue;

  resultForCb.topicsComplete = true;

  const catsOk = expectedFaqs.every(cfg => {
    const entry = found[cfg.question];
    return entry.category && entry.category.name === cfg.categoryName;
  });
  resultForCb.correctCategories = catsOk;

  resultForCb.exactlyThree = cbArticles.length === 3;

  if (!bestResult) {
    bestResult = resultForCb;
  } else if (resultForCb.topicsComplete && !bestResult.topicsComplete) {
    bestResult = resultForCb;
  }
}

const hasTopicsComplete = !!(bestResult && bestResult.topicsComplete);
const hasCorrectCategories = !!(bestResult && bestResult.topicsComplete && bestResult.correctCategories);
const hasExactlyThree = !!(bestResult && bestResult.topicsComplete && bestResult.exactlyThree);

// CP1 (0.4): One chatbot has all three required FAQ entries with the exact questions and answers
checkpoints.push({ passed: hasTopicsComplete, weight: 0.4 });

// CP2 (0.3): Those three entries are assigned to the correct categories (Shipping, Returns, Orders)
checkpoints.push({ passed: hasCorrectCategories, weight: 0.3 });

// CP3 (0.3): That chatbot has exactly three FAQ articles total (no extra FAQs beyond the requested three)
checkpoints.push({ passed: hasExactlyThree, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const appearances = JSON.parse(localStorage.getItem('chatbot_appearances') || '[]');
const chatbots = JSON.parse(localStorage.getItem('chatbots') || '[]');

const matchingAppearance = appearances.find(a => (
  a.accent_color === '#1A73E8' &&
  a.position === 'bottom_right' &&
  a.header_title === 'Need help with your order?' &&
  a.show_title === true &&
  chatbots.some(cb => cb.id === a.chatbot_id)
));

// Single checkpoint (1.0): At least one existing chatbot has widget appearance configured exactly as required
checkpoints.push({ passed: !!matchingAppearance, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const rules = JSON.parse(localStorage.getItem('routing_rules') || '[]');
const teams = JSON.parse(localStorage.getItem('teams') || '[]');

let hasHoursAndTeamRule = false;
let hasFullRule = false;

const expectedDaysSorted = ['mon', 'tue', 'wed', 'thu', 'fri'].sort();

for (const rule of rules) {
  const days = (rule.days_of_week || []).map(d => String(d).toLowerCase()).sort();

  const hoursOk = (
    rule.condition_type === 'business_hours' &&
    rule.start_time === '09:00' &&
    rule.end_time === '17:00' &&
    days.length === expectedDaysSorted.length &&
    JSON.stringify(days) === JSON.stringify(expectedDaysSorted)
  );

  if (!hoursOk) continue;

  const team = teams.find(t => t.id === rule.match_team_id) || null;
  const teamDesc = (team && team.description ? team.description : '').toLowerCase();

  const teamOk = (
    rule.match_action_type === 'route_to_team' &&
    !!team &&
    teamDesc.includes('pre-sales') &&
    teamDesc.includes('pricing')
  );

  if (teamOk) {
    hasHoursAndTeamRule = true;

    const fullOk = (
      rule.fallback_action_type === 'bot_only' &&
      rule.status === 'enabled' &&
      rule.name === 'Weekday Sales Hours'
    );

    if (fullOk) {
      hasFullRule = true;
    }
  }
}

// CP1 (0.4): There exists a business-hours rule for Mon–Fri 09:00–17:00 that routes matching chats to a team whose description includes both 'pre-sales' and 'pricing'
checkpoints.push({ passed: hasHoursAndTeamRule, weight: 0.4 });

// CP2 (0.6): That same rule is enabled, named 'Weekday Sales Hours', and uses 'bot_only' as the fallback action for all other times
checkpoints.push({ passed: hasFullRule, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const forms = JSON.parse(localStorage.getItem('lead_capture_forms') || '[]');
const fields = JSON.parse(localStorage.getItem('lead_capture_fields') || '[]');
const chatbots = JSON.parse(localStorage.getItem('chatbots') || '[]');

let hasFieldsForm = false;
let hasOrderedForm = false;

for (const form of forms) {
  if (!form.enabled) continue;
  if (!chatbots.some(cb => cb.id === form.chatbot_id)) continue; // ensure it's attached to an existing chatbot

  const formFields = fields.filter(f => f.form_id === form.id);

  const fullNameField = formFields.find(f => f.label === 'Full Name' && f.field_type === 'text' && f.required === true);
  const emailField = formFields.find(f => f.label === 'Email' && f.field_type === 'email' && f.required === true);
  const companyField = formFields.find(f => f.label === 'Company' && f.field_type === 'text' && f.required === false);

  const fieldsOk = !!(fullNameField && emailField && companyField);
  if (!fieldsOk) continue;

  hasFieldsForm = true;

  const orderOk = (
    typeof fullNameField.order_index === 'number' &&
    typeof emailField.order_index === 'number' &&
    typeof companyField.order_index === 'number' &&
    fullNameField.order_index === 1 &&
    emailField.order_index === 2 &&
    companyField.order_index === 3
  );

  if (orderOk) {
    hasOrderedForm = true;
    break; // we found a fully-correct form
  }
}

// CP1 (0.5): Some enabled lead capture form on an existing chatbot has the three required fields with correct labels, types, and required/optional settings
checkpoints.push({ passed: hasFieldsForm, weight: 0.5 });

// CP2 (0.5): For such a form, the fields appear in the correct order (Full Name first, then Email, then Company) via order_index 1,2,3
checkpoints.push({ passed: hasOrderedForm, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const filterParams = JSON.parse(localStorage.getItem('task7_prevMonthFilterParams') || 'null');
const opened = JSON.parse(localStorage.getItem('task7_prevMonthTopDayOpened') || 'null');
const summaries = JSON.parse(localStorage.getItem('daily_analytics_summaries') || '[]');

// Reproduce the "previous month" date range logic used in getAnalyticsDateRangePresets
function formatDate(d) {
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return `${y}-${m}-${day}`;
}

const today = new Date();
const currentMonth = today.getMonth(); // 0-based
const currentYear = today.getFullYear();
let prevMonth, prevYear;
if (currentMonth === 0) {
  prevMonth = 11;
  prevYear = currentYear - 1;
} else {
  prevMonth = currentMonth - 1;
  prevYear = currentYear;
}
const startDateObj = new Date(prevYear, prevMonth, 1);
const endDateObj = new Date(prevYear, prevMonth + 1, 0);
const expectedStart = formatDate(startDateObj);
const expectedEnd = formatDate(endDateObj);

// CP1 (0.4): User applied a filter matching the previous full calendar month for all chatbots
const cp1Passed = !!(
  filterParams &&
  filterParams.startDate === expectedStart &&
  filterParams.endDate === expectedEnd &&
  (filterParams.chatbotId === null || filterParams.chatbotId === undefined)
);
checkpoints.push({ passed: cp1Passed, weight: 0.4 });

// Filter summaries to that previous month and all-chatbots scope (chatbot_id null)
const summariesInRange = summaries.filter(s => {
  if (!s || !s.date) return false;
  const d = new Date(s.date);
  if (isNaN(d.getTime())) return false;
  return (
    d >= startDateObj &&
    d <= endDateObj &&
    (s.chatbot_id === null || s.chatbot_id === undefined)
  );
});

// Determine the top day by average_messages_per_conversation
let topSummary = null;
for (const s of summariesInRange) {
  if (!topSummary || Number(s.average_messages_per_conversation || 0) > Number(topSummary.average_messages_per_conversation || 0)) {
    topSummary = s;
  }
}

// CP2 (0.3): User opened detail for some day in that previous month range at the all-chatbots level
let cp2Passed = false;
if (opened && opened.dailySummaryId && summariesInRange.length > 0) {
  const summary = summariesInRange.find(s => s.id === opened.dailySummaryId) || null;
  if (summary) {
    const d = new Date(summary.date);
    cp2Passed = (
      d >= startDateObj &&
      d <= endDateObj &&
      (summary.chatbot_id === null || summary.chatbot_id === undefined)
    );
  }
}
checkpoints.push({ passed: cp2Passed, weight: 0.3 });

// CP3 (0.3): The opened day's summary is the one with the highest average_messages_per_conversation in that range
const cp3Passed = !!(
  opened &&
  topSummary &&
  opened.dailySummaryId === topSummary.id
);
checkpoints.push({ passed: cp3Passed, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const teamMembers = JSON.parse(localStorage.getItem('team_members') || '[]');
const chatbotMembers = JSON.parse(localStorage.getItem('chatbot_members') || '[]');
const chatbots = JSON.parse(localStorage.getItem('chatbots') || '[]');

const alex = teamMembers.find(m => m.email === 'alex.admin@example.com');
const emma = teamMembers.find(m => m.email === 'emma.editor@example.com');

const alexOk = !!(alex && alex.name === 'Alex Admin' && alex.role === 'admin');
const emmaOk = !!(emma && emma.name === 'Emma Editor' && emma.role === 'editor');

// CP1 (0.4): Both Alex and Emma were invited with correct names, emails, and roles (admin for Alex, editor for Emma)
const cp1Passed = alexOk && emmaOk;
checkpoints.push({ passed: cp1Passed, weight: 0.4 });

// CP2 (0.6): Emma (the lower-permission member) is assigned as a collaborator on at least one existing chatbot with editor permission
let collabOk = false;
if (emmaOk) {
  for (const cm of chatbotMembers) {
    if (cm.team_member_id === emma.id && cm.permission_level === 'editor' && chatbots.some(cb => cb.id === cm.chatbot_id)) {
      collabOk = true;
      break;
    }
  }
}
checkpoints.push({ passed: collabOk, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
